#include <stdio.h>

/* Deklaracija strukture */
struct Student {
    char ime[30];
    int indeks;
    double prosjek;
};

/* Funkcija za unos studenta */
struct Student unesi_studenta() {
    struct Student s;

    printf("Unesite ime: ");
    scanf("%29s", s.ime);

    printf("Unesite broj indeksa: ");
    scanf("%d", &s.indeks);

    printf("Unesite prosjek: ");
    scanf("%lf", &s.prosjek);

    return s;
}

/* Funkcija za ispis studenta */
void ispisi_studenta(struct Student s) {
    printf("Ime: %s\n", s.ime);
    printf("Indeks: %d\n", s.indeks);
    printf("Prosjek: %.2f\n", s.prosjek);
}

int main(void) {
    struct Student s1 = unesi_studenta();
    struct Student s2 = unesi_studenta();

    printf("\n--- Ispis studenata ---\n");
    ispisi_studenta(s1);
    printf("\n");
    ispisi_studenta(s2);

    return 0;
}
